<?php
/**
 * Template Name: Custom Content Layout
 * Template Post Type: post, page, custom_post_type_slug
 *
 * This template displays the post content along with custom HTML content
 * stored in a 'custom_content' post meta field.
 */

get_header();

while ( have_posts() ) :
	the_post();

	$post_id = get_the_ID();
	$custom_content = get_post_meta( $post_id, 'custom_content', true );
	?>

	<article id="post-<?php the_ID(); ?>" <?php post_class(); ?>>
		<header class="entry-header">
			<?php the_title( '<h1 class="entry-title">', '</h1>' ); ?>
		</header><!-- .entry-header -->

		<div class="entry-content">
			<?php
			// Display the standard post content
			the_content();

			// Display the custom HTML content from the meta field
			if ( ! empty( $custom_content ) ) {
				echo $custom_content;
			}

			wp_link_pages(
				array(
					'before' => '<div class="page-links">' . esc_html__( 'Pages:', 'your-text-domain' ),
					'after'  => '</div>',
				)
			);
			?>
		</div><!-- .entry-content -->

		<footer class="entry-footer">
			<?php
			// You can add post meta information here, e.g., categories, tags, author, date
			// edit_post_link( esc_html__( 'Edit', 'your-text-domain' ), '<span class="edit-link">', '</span>' );
			?>
		</footer><!-- .entry-footer -->
	</article><!-- #post-<?php the_ID(); ?> -->

	<?php
	// If comments are open or we have at least one comment, load up the comment template.
	if ( comments_open() || get_comments_number() ) :
		comments_template();
	endif;

endwhile; // End of the loop.

